import { buildSectionPage } from '../../utils/section-page.utils.js';
import { API_URL } from '../../config.js';
import {
    queryRecentClientLogs,
    flushClientLogBatch,
    pushClientLogEntry,
} from '../../services/debug/client-log-buffer.js';
import { deleteAllClientLogs, getRecentClientLogs } from '../../services/debug/client-log-store.js';
import { checkClientLogShippingAvailability } from '../../services/debug/client-log-shipping.js';
import { getDeviceId, getDeviceLabel, setDeviceLabel } from '../../services/debug/device-identity.js';
import {
    getSwStatus, unregisterSw, updateSw, skipWaiting,
    type SwStatus,
} from '../../services/debug/sw-controls.js';
import {
    listCaches, listDatabases, clearAllCaches, deleteAllDatabases, nukeAndReload,
} from '../../services/debug/storage-controls.js';
import {
    snapshotConnectivity, pingBackend, type PingResult,
} from '../../services/debug/connectivity.js';
import {
    snapshotInstall, queryPermissions, requestNotificationPermission, persistStorage,
    isStoragePersisted, DEFAULT_PERMISSION_NAMES,
} from '../../services/debug/install-info.js';
import { collectDbInfo, formatBytes } from '../../services/debug/db-info.js';
import { DbService } from '../../db/db.service.js';
import { SyncService } from '../../services/sync/sync.service.js';
import { downloadAndLoadSnapshot } from '../../db/db-snapshot.service.js';
import '../log-viewer/log-viewer.component.js';
import type { LogViewer } from '../log-viewer/log-viewer.component.js';
import type { ScreenComponent } from '../../types/screen-component.js';

export class DebugScreen extends HTMLElement implements ScreenComponent {
    setLoading(): void {}
    setError(err: unknown): void {}
    clearStatus(): void {}
    private initialized = false;
    private connectivityTimer: ReturnType<typeof setInterval> | null = null;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Debug', 'extra', '/debug');
        const intro = document.createElement('p');
        intro.textContent = 'In-app diagnostics. All errors are shown raw so they are instantly actionable on mobile.';
        page.content.appendChild(intro);

        page.content.appendChild(this.buildLogsPanel());
        page.content.appendChild(this.buildConnectivityPanel());
        page.content.appendChild(this.buildDatabasePanel());
        page.content.appendChild(this.buildInstallPanel());
        page.content.appendChild(this.buildSwPanel());
        page.content.appendChild(this.buildStoragePanel());
    }

    disconnectedCallback(): void {
        if (this.connectivityTimer) {
            clearInterval(this.connectivityTimer);
            this.connectivityTimer = null;
        }
    }

    // ── Logs ────────────────────────────────────────────────────────────────

    private buildLogsPanel(): HTMLElement {
        const details = makePanel('Client Logs', true);

        // Shipping availability — fail-loud surface for the SW/Background
        // Sync gate. Populated on first paint and the user can re-check.
        const statusEl = document.createElement('div');
        statusEl.className = 'debug-shipping-status';
        statusEl.dataset.testid = 'logs-shipping-status';
        details.appendChild(statusEl);

        const refreshShipping = async () => {
            const status = await checkClientLogShippingAvailability();
            statusEl.textContent = status.ok
                ? 'Shipping: ok (Background Sync API registered)'
                : `Shipping: BROKEN — ${status.error}`;
            statusEl.classList.toggle('ok', status.ok);
            statusEl.classList.toggle('broken', !status.ok);
        };
        void refreshShipping();

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';

        const refreshBtn = makeButton('Refresh', async () => {
            await refreshShipping();
            viewer.refresh();
        }, 'logs-refresh');
        const downloadBtn = makeButton('Download .txt', () => this.handleDownloadLogs(), 'logs-download');
        const clearBtn = makeButton('Clear buffer', async () => {
            await deleteAllClientLogs();
            // Visible marker so the clear is obvious even when polling
            // keeps feeding the store seconds later.
            pushClientLogEntry({ level: 'info', module: 'debug', message: '— buffer cleared —' });
            await flushClientLogBatch();
            viewer.refresh();
        }, 'logs-clear');

        toolbar.append(refreshBtn, downloadBtn, clearBtn);
        details.appendChild(toolbar);

        const viewer = document.createElement('log-viewer') as LogViewer;
        viewer.availableLevels = ['debug', 'info', 'warn', 'error'];
        viewer.source = async (filters) => queryRecentClientLogs(filters);
        details.appendChild(viewer);

        return details;
    }

    private async handleDownloadLogs(): Promise<void> {
        await flushClientLogBatch();
        const response = await getRecentClientLogs(10_000);
        const text = response.entries.map((e) => JSON.stringify(e)).join('\n') + '\n';
        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `motivation-client-logs-${Temporal.Now.instant().toString()}.txt`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(() => URL.revokeObjectURL(url), 1000);
    }

    // ── Connectivity ────────────────────────────────────────────────────────

    private buildConnectivityPanel(): HTMLElement {
        const details = makePanel('Connectivity', true);

        const statusEl = makeCodeBlock();
        details.appendChild(statusEl);

        const pingResultEl = makeCodeBlock();
        pingResultEl.textContent = 'No ping yet.';
        details.appendChild(pingResultEl);

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        const pingBtn = makeButton('Ping backend', async () => {
            pingResultEl.textContent = `Pinging ${pingUrl()}…`;
            const result = await pingBackend(pingUrl());
            pingResultEl.textContent = formatPingResult(pingUrl(), result);
        }, 'connectivity-ping');
        toolbar.appendChild(pingBtn);
        details.appendChild(toolbar);

        const render = () => {
            const snap = snapshotConnectivity();
            statusEl.textContent = JSON.stringify(snap, null, 2);
        };
        render();
        this.connectivityTimer = setInterval(render, 2000);

        return details;
    }

    // ── Database (OPFS + Sync) ─────────────────────────────────────────────

    private buildDatabasePanel(): HTMLElement {
        const details = makePanel('Database', true);

        const summaryEl = makeCodeBlock();
        summaryEl.textContent = 'Loading…';
        details.appendChild(summaryEl);

        const detailsEl = makeCodeBlock();
        details.appendChild(detailsEl);

        const outputEl = makeCodeBlock();
        outputEl.textContent = '';
        details.appendChild(outputEl);

        const refresh = async () => {
            summaryEl.textContent = 'Loading…';
            try {
                const info = await collectDbInfo({
                    driver: DbService.getInstance().driver,
                    storage: typeof navigator !== 'undefined' ? navigator.storage : undefined,
                });
                const usagePct = info.storage?.usage != null && info.storage.quota
                    ? `${((info.storage.usage / info.storage.quota) * 100).toFixed(2)}%`
                    : 'unknown';
                summaryEl.textContent = [
                    `DB size:         ${formatBytes(info.sizeBytes)} (${info.pageCount ?? '?'} × ${info.pageSize ?? '?'} bytes/page)`,
                    `Pending changes: ${info.pendingChanges ?? '?'}`,
                    `Storage used:    ${formatBytes(info.storage?.usage ?? null)} of ${formatBytes(info.storage?.quota ?? null)} (${usagePct})`,
                    `OPFS persisted:  ${info.storage?.persisted ?? 'unknown'}`,
                ].join('\n');
                detailsEl.textContent = JSON.stringify({ tables: info.tables, driverError: info.driverError }, null, 2);
            } catch (err) {
                const msg = err instanceof Error ? (err.stack ?? err.message) : String(err);
                summaryEl.textContent = `Failed to collect DB info: ${msg}`;
                detailsEl.textContent = '';
            }
        };

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        toolbar.append(
            makeButton('Refresh', refresh, 'db-refresh'),
            makeButton('Pull snapshot', async () => {
                outputEl.textContent = 'Downloading snapshot…';
                try {
                    const loaded = await downloadAndLoadSnapshot({ dbService: DbService.getInstance() });
                    outputEl.textContent = JSON.stringify({ loaded }, null, 2);
                } catch (err) {
                    outputEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
                }
                await refresh();
            }, 'db-pull-snapshot'),
            makeButton('Sync (push + pull)', async () => {
                outputEl.textContent = 'Syncing…';
                try {
                    const result = await SyncService.syncPendingChanges();
                    outputEl.textContent = JSON.stringify(result, null, 2);
                } catch (err) {
                    outputEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
                }
                await refresh();
            }, 'db-sync'),
        );
        details.appendChild(toolbar);

        void refresh();
        return details;
    }

    // ── Install & Permissions ───────────────────────────────────────────────

    private buildInstallPanel(): HTMLElement {
        const details = makePanel('Install & Permissions', true);

        const installEl = makeCodeBlock();
        const permissionsEl = makeCodeBlock();

        // Device identity row — used as the device fields stamped on every
        // client log entry shipped to the server.
        const deviceRow = document.createElement('div');
        deviceRow.className = 'debug-device-row';
        const deviceIdLabel = document.createElement('div');
        deviceIdLabel.dataset.testid = 'device-id';
        const labelInput = document.createElement('input');
        labelInput.type = 'text';
        labelInput.dataset.testid = 'device-label';
        labelInput.className = 'debug-input';
        labelInput.addEventListener('change', () => {
            const value = labelInput.value.trim();
            if (!value) {
                labelInput.value = getDeviceLabel();
                return;
            }
            setDeviceLabel(value);
        });
        deviceRow.append(deviceIdLabel, labelInput);
        details.appendChild(deviceRow);

        const outputEl = makeCodeBlock();
        details.append(installEl, permissionsEl, outputEl);

        const refresh = async () => {
            deviceIdLabel.textContent = `device_id: ${getDeviceId()}`;
            labelInput.value = getDeviceLabel();
            installEl.textContent = JSON.stringify({
                ...snapshotInstall(),
                storagePersisted: await isStoragePersisted(),
            }, null, 2);
            permissionsEl.textContent = JSON.stringify(
                await queryPermissions(DEFAULT_PERMISSION_NAMES),
                null, 2,
            );
        };

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        toolbar.append(
            makeButton('Refresh', refresh, 'install-refresh'),
            makeButton('Request notifications', async () => {
                outputEl.textContent = JSON.stringify(await requestNotificationPermission(), null, 2);
                await refresh();
            }, 'install-request-notifications'),
            makeButton('Persist storage', async () => {
                outputEl.textContent = JSON.stringify(await persistStorage(), null, 2);
                await refresh();
            }, 'install-persist-storage'),
        );
        details.appendChild(toolbar);

        void refresh();
        return details;
    }

    // ── Service Worker ──────────────────────────────────────────────────────

    private buildSwPanel(): HTMLElement {
        const details = makePanel('Service Worker', true);

        const statusEl = makeCodeBlock();
        statusEl.textContent = 'Loading…';
        details.appendChild(statusEl);

        const outputEl = makeCodeBlock();
        outputEl.textContent = '';
        details.appendChild(outputEl);

        const renderStatus = async () => {
            const result = await getSwStatus();
            statusEl.textContent = JSON.stringify(result, null, 2);
        };

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        toolbar.append(
            makeButton('Refresh status', renderStatus, 'sw-refresh'),
            makeButton('Update', async () => {
                outputEl.textContent = JSON.stringify(await updateSw(), null, 2);
                await renderStatus();
            }, 'sw-update'),
            makeButton('Skip waiting', async () => {
                outputEl.textContent = JSON.stringify(await skipWaiting(), null, 2);
                await renderStatus();
            }, 'sw-skip-waiting'),
            makeButton('Unregister', async () => {
                if (!confirm('Unregister the service worker?')) return;
                outputEl.textContent = JSON.stringify(await unregisterSw(), null, 2);
                await renderStatus();
            }, 'sw-unregister'),
        );
        details.appendChild(toolbar);

        void renderStatus();
        return details;
    }

    // ── Storage ─────────────────────────────────────────────────────────────

    private buildStoragePanel(): HTMLElement {
        const details = makePanel('Storage', true);

        const cachesEl = makeCodeBlock();
        cachesEl.textContent = 'Loading caches…';
        details.appendChild(cachesEl);

        const dbsEl = makeCodeBlock();
        dbsEl.textContent = 'Loading IndexedDB…';
        details.appendChild(dbsEl);

        const outputEl = makeCodeBlock();
        outputEl.textContent = '';
        details.appendChild(outputEl);

        const refresh = async () => {
            cachesEl.textContent = JSON.stringify(await listCaches(), null, 2);
            dbsEl.textContent = JSON.stringify(await listDatabases(), null, 2);
        };

        const toolbar = document.createElement('div');
        toolbar.className = 'debug-toolbar';
        toolbar.append(
            makeButton('Refresh', refresh, 'storage-refresh'),
            makeButton('Clear caches', async () => {
                if (!confirm('Delete all Cache Storage entries?')) return;
                outputEl.textContent = JSON.stringify(await clearAllCaches(), null, 2);
                await refresh();
            }, 'storage-clear-caches'),
            makeButton('Delete IDB', async () => {
                if (!confirm('Delete all IndexedDB databases?')) return;
                outputEl.textContent = JSON.stringify(await deleteAllDatabases(), null, 2);
                await refresh();
            }, 'storage-delete-idb'),
            makeButton('Nuke & reload', async () => {
                if (!confirm('Unregister SW, clear all caches and IDB, then reload?')) return;
                await nukeAndReload();
            }, 'storage-nuke'),
        );
        details.appendChild(toolbar);

        void refresh();
        return details;
    }
}

function pingUrl(): string {
    return `${API_URL}/health`;
}

function formatPingResult(url: string, r: PingResult): string {
    return JSON.stringify({ url, ...r }, null, 2);
}

function makePanel(title: string, open: boolean): HTMLDetailsElement {
    const details = document.createElement('details');
    details.className = 'debug-panel';
    details.open = open;
    const summary = document.createElement('summary');
    summary.textContent = title;
    details.appendChild(summary);
    return details;
}

function makeButton(label: string, onClick: () => void | Promise<void>, testId?: string): HTMLButtonElement {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'debug-btn';
    btn.textContent = label;
    if (testId) btn.dataset.testid = testId;
    btn.addEventListener('click', () => { void onClick(); });
    return btn;
}

function makeCodeBlock(): HTMLPreElement {
    const pre = document.createElement('pre');
    pre.className = 'debug-code';
    return pre;
}

if (!customElements.get('debug-screen')) {
    customElements.define('debug-screen', DebugScreen);
}
