import type { DbDriver } from '@motivation/shared';

export interface TableRowCount {
    name: string;
    rows: number;
}

export interface DbStorageEstimate {
    usage: number | null;
    quota: number | null;
    persisted: boolean;
}

export interface DbInfo {
    sizeBytes: number | null;
    pageCount: number | null;
    pageSize: number | null;
    pendingChanges: number | null;
    tables: TableRowCount[];
    storage: DbStorageEstimate | null;
    driverError?: string;
}

const INTERESTING_TABLES = [
    '_pending_changes',
    'nutrition_logs',
    'food_library_items',
    'activities',
    'goals',
    'cards',
    'decks',
    'reviews',
];

interface CollectOptions {
    driver: DbDriver;
    storage: StorageManager | undefined;
}

export async function collectDbInfo(options: CollectOptions): Promise<DbInfo> {
    const { driver, storage } = options;
    const info: DbInfo = {
        sizeBytes: null,
        pageCount: null,
        pageSize: null,
        pendingChanges: null,
        tables: [],
        storage: null,
    };

    try {
        const [pageCountRow] = await driver.query<{ value: number }>('PRAGMA page_count');
        const [pageSizeRow] = await driver.query<{ value: number }>('PRAGMA page_size');
        const pageCount = Number(pageCountRow?.value ?? 0);
        const pageSize = Number(pageSizeRow?.value ?? 0);
        info.pageCount = pageCount;
        info.pageSize = pageSize;
        info.sizeBytes = pageCount * pageSize;

        const existing = await driver.query<{ name: string }>(
            `SELECT name FROM sqlite_master WHERE type='table' AND name IN (${INTERESTING_TABLES.map(() => '?').join(',')})`,
            ...INTERESTING_TABLES,
        );
        const existingNames = new Set(existing.map((r) => r.name));

        for (const name of INTERESTING_TABLES) {
            if (!existingNames.has(name)) continue;
            const [row] = await driver.query<{ count: number }>(`SELECT COUNT(*) AS count FROM "${name}"`);
            const rows = Number(row?.count ?? 0);
            info.tables.push({ name, rows });
            if (name === '_pending_changes') info.pendingChanges = rows;
        }
    } catch (err) {
        info.driverError = err instanceof Error ? err.message : String(err);
    }

    if (storage?.estimate) {
        try {
            const est = await storage.estimate();
            const persisted = storage.persisted ? await storage.persisted() : false;
            info.storage = {
                usage: typeof est.usage === 'number' ? est.usage : null,
                quota: typeof est.quota === 'number' ? est.quota : null,
                persisted,
            };
        } catch (err) {
            info.storage = { usage: null, quota: null, persisted: false };
            info.driverError = info.driverError
                ? `${info.driverError}; storage: ${(err as Error).message}`
                : `storage: ${(err as Error).message}`;
        }
    }

    return info;
}

export function formatBytes(bytes: number | null): string {
    if (bytes == null) return 'unknown';
    const units = ['B', 'KB', 'MB', 'GB'];
    let value = bytes;
    let unit = 0;
    while (value >= 1024 && unit < units.length - 1) {
        value /= 1024;
        unit++;
    }
    return `${value.toFixed(value >= 100 ? 0 : value >= 10 ? 1 : 2)} ${units[unit]}`;
}
